    Licenses='["MIT"]' OR Licenses='["MIT "]' OR Licenses='["MIT License"]' OR Licenses='["MIT license"]'
    OR Licenses LIKE '%"MIT"%'
  )
  AND (
    VersionInfo LIKE '%"IsRelease"%true%' OR VersionInfo LIKE '%"IsRelease":true%'
  );

